const FILTERS: { f: Filter; label: string }[] = [
  { f: "all", label: "All" },
  { f: "ongoing", label: "Ongoing" },
  { f: "made", label: "Made something" },
  { f: "pinned", label: "Pinned" },
];

function ConvCard({ conv }: { conv: Conv }) {
  const router = useRouter();
  // Opening or continuing a conversation lands in the Conversation surface.
  const open = () => router.push("/study");
  return (
    <div className={`conv${conv.ongoing ? " ongoing" : ""}`} data-tags={conv.tags.join(" ")} onClick={open}>
      <div className="conv-row">
        <div className="conv-body">
          <div className="conv-top">
            {conv.pinned && (
              <span className="pin">
                <svg viewBox="0 0 24 24">
                  <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z" />
                </svg>
              </span>
            )}
            <span className="conv-title">{conv.title}</span>
            {conv.ongoing && (
              <span className="tag-ongoing">
                <span className="d" />
                Ongoing
              </span>
            )}
          </div>
          <div className="conv-sum">
            {conv.verdict && <span className="v">{conv.verdict}</span>}
            {conv.rest}
          </div>
          <div className="conv-foot">
            <span className="conv-meta">{conv.meta}</span>
            {conv.made && (
              <>
                <span className="sep-dot" />
                <a className="conv-made">
                  <ArrowOut />
                  {conv.made}
                </a>
              </>
            )}
          </div>
        </div>
        <button className="conv-cont" type="button">
          Continue
          <ArrowRight />
        </button>
      </div>
    </div>
  );
}

export function StudyConversations() {
  const [filter, setFilter] = useState<Filter>("all");

  const matches = (conv: Conv) => filter === "all" || conv.tags.includes(filter);

  return (
    <div className="study-conversations">
      <div className="ambient" />

      <div className="scroll">
        <div className="col">
          <div className="c-title">Conversations</div>
          <div className="c-stat">
            290 conversations<span className="sep" />
            <b>3 ongoing</b>
            <span className="sep" />
            everything you&rsquo;ve thought through with Magellan
          </div>

          {/* ask bar — the summon */}
          <div className="ask">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
              <circle cx="11" cy="11" r="7" />
              <line x1="21" y1="21" x2="16.65" y2="16.65" />
            </svg>
            <input placeholder="Find a conversation — by topic, by what it made, or just describe it…" />
            <span className="kbd">⌘K</span>
          </div>

          <div className="c-filters">
            {FILTERS.map((c) => (
              <button
                key={c.f}
                className={`fchip${filter === c.f ? " active" : ""}`}
                type="button"
                onClick={() => setFilter(c.f)}
              >
                {c.label}
              </button>
            ))}
            <span className="c-sort">Most recent</span>
          </div>

          {GROUPS.map((g) => {
            const visible = g.items.filter(matches);
            return (
              <div key={g.when} className="grp" data-when={g.when} hidden={visible.length === 0}>
                <div className="grp-label">
                  {g.label}
                  <span className="grp-rule" />
                </div>
                <div className="list">
                  {visible.map((conv) => (
                    <ConvCard key={conv.id} conv={conv} />
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
